class ArticleRepository(
    private val articleDao: ArticleDao,
    private val articleApi: ArticleApi
) {
    // Single source of truth: local database
    fun observeArticles(): Flow<List<Article>> = articleDao.observeAll()

    suspend fun refresh() {
        try {
            val remoteArticles = articleApi.fetchArticles()
            articleDao.upsertAll(remoteArticles)
        } catch (e: IOException) {
            // Network failed — local data is still available
            // Optionally emit an error state
        }
    }

    // Convenience: observe + trigger refresh
    fun observeAndRefresh(): Flow<List<Article>> = flow {
        // Emit local data immediately
        emitAll(articleDao.observeAll())
    }.onStart {
        // Trigger background sync
        try { refresh() } catch (_: Exception) {}
    }
}
